head.b:skin:
/* ============================================================
   AFRICAN PRINCESS LABEL — PREMIUM OPTIMIZED THEME v2.0
   Concept: Simon Guyashi | Optimized: Premium Edition
   ============================================================ */

:root {
  --royal-pink: #e91e8c;
  --deep-pink: #c2185b;
  --rose-gold: #b76e79;
  --soft-pink: #f48fb1;
  --lavender-pink: #f8bbd9;
  --blush: #fce4ec;
  --cream: #fff9f5;
  --milk-white: #fdf6f0;
  --gold: #d4a843;
  --gold-light: #f7d976;
  --gold-shimmer: #ffeaa0;
  --peach: #ffccbc;
  --soft-purple: #ce93d8;
  --luxury-black: #0a0508;
  --dark-surface: #120a10;
  --dark-card: #1a0c18;
  --glass-bg: rgba(255,255,255,0.06);
  --glass-border: rgba(255,192,203,0.18);
  --shadow-glow: 0 0 40px rgba(233,30,140,0.3);
  --font-display: 'Playfair Display', serif;
  --font-body: 'Montserrat', sans-serif;
  --font-elegant: 'Cormorant Garamond', serif;
  --font-script: 'Dancing Script', cursive;
  --transition-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --transition-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* ============ RESET & BASE ============ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  overflow-x: hidden;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-body);
  background: var(--luxury-black);
  color: var(--cream);
  overflow-x: hidden;
  cursor: none;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

/* ============ IMAGE QUALITY ============ */
img {
  display: block;
  max-width: 100%;
  image-rendering: -webkit-optimize-contrast;
  image-rendering: high-quality;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
}

/* ============ CUSTOM CURSOR ============ */
#custom-cursor {
  position: fixed;
  width: 10px; height: 10px;
  background: var(--royal-pink);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99999;
  will-change: transform;
  transform: translateZ(0);
  box-shadow: 0 0 16px var(--royal-pink), 0 0 30px rgba(233,30,140,0.4);
  transition: width 0.2s ease, height 0.2s ease, opacity 0.2s ease;
}
#cursor-follower {
  position: fixed;
  width: 32px; height: 32px;
  border: 1.5px solid rgba(233,30,140,0.45);
  border-radius: 50%;
  pointer-events: none;
  z-index: 99998;
  will-change: transform;
  transform: translateZ(0);
  transition: border-color 0.25s ease;
}
body:not(.has-mouse) #custom-cursor,
body:not(.has-mouse) #cursor-follower { display: none; }

/* ============ PRELOADER ============ */
#preloader {
  position: fixed;
  inset: 0;
  background: var(--luxury-black);
  z-index: 99997;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}
.preloader-bg {
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at 50% 60%, rgba(233,30,140,0.12) 0%, transparent 65%);
  animation: preloaderPulse 3s ease-in-out infinite;
  will-change: opacity;
}
@keyframes preloaderPulse {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 1; }
}
.preloader-crown {
  width: 90px; height: 90px;
  margin-bottom: 28px;
  animation: crownFloat 3.5s ease-in-out infinite;
  filter: drop-shadow(0 0 18px rgba(233,30,140,0.7));
  will-change: transform;
  transform: translateZ(0);
}
@keyframes crownFloat {
  0%, 100% { transform: translateY(0) scale(1); }
  50% { transform: translateY(-12px) scale(1.04); }
}
.preloader-title {
  font-family: var(--font-display);
  font-size: clamp(1.4rem, 4vw, 2rem);
  font-weight: 700;
  background: linear-gradient(135deg, var(--gold) 0%, var(--royal-pink) 50%, var(--gold-light) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  background-size: 200% auto;
  text-align: center;
  letter-spacing: 4px;
  margin-bottom: 6px;
  animation: shimmerText 2.5s linear infinite;
  will-change: background-position;
}
@keyframes shimmerText {
  0% { background-position: 0% center; }
  100% { background-position: 200% center; }
}
.preloader-sub {
  font-family: var(--font-body);
  font-size: 0.6rem;
  letter-spacing: 7px;
  color: var(--soft-pink);
  text-transform: uppercase;
  margin-bottom: 44px;
  opacity: 0.75;
}
.preloader-bar-wrap {
  width: min(260px, 70vw);
  height: 2px;
  background: rgba(255,255,255,0.08);
  border-radius: 10px;
  overflow: hidden;
  margin-bottom: 12px;
}
.preloader-bar {
  height: 100%;
  width: 0;
  background: linear-gradient(90deg, var(--royal-pink), var(--gold), var(--soft-pink));
  border-radius: 10px;
  box-shadow: 0 0 8px var(--royal-pink);
  transition: width 0.08s linear;
}
.preloader-percent {
  font-family: var(--font-body);
  font-size: 0.7rem;
  color: rgba(255,255,255,0.45);
  letter-spacing: 3px;
}
.preloader-particles {
  position: absolute;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
}
.preloader-particle {
  position: absolute;
  border-radius: 50%;
  opacity: 0;
  animation: particleDrift linear infinite;
  will-change: transform, opacity;
}
@keyframes particleDrift {
  0% { transform: translateY(100vh) translateX(0); opacity: 0; }
  8% { opacity: 0.8; }
  92% { opacity: 0.4; }
  100% { transform: translateY(-30px) translateX(20px); opacity: 0; }
}

/* ============ HEADER ============ */
#site-header {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 1000;
  padding: 0 48px;
  height: 78px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  transition: background 0.4s ease, height 0.3s ease, backdrop-filter 0.4s ease;
  will-change: background;
}
#site-header.scrolled {
  background: rgba(8,4,7,0.88);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border-bottom: 1px solid rgba(233,30,140,0.12);
  box-shadow: 0 4px 24px rgba(0,0,0,0.4);
  height: 66px;
}
.header-logo img {
  height: 46px;
  width: auto;
  object-fit: contain;
  transition: filter 0.3s ease, transform 0.3s ease;
  will-change: transform;
}
.header-logo img:hover {
  transform: scale(1.05) translateZ(0);
  filter: drop-shadow(0 0 10px rgba(233,30,140,0.6));
}
.nav-menu {
  display: flex;
  align-items: center;
  gap: 32px;
  list-style: none;
}
.nav-menu a {
  font-family: var(--font-body);
  font-size: 0.68rem;
  font-weight: 500;
  letter-spacing: 2.5px;
  text-transform: uppercase;
  color: rgba(255,255,255,0.82);
  text-decoration: none;
  position: relative;
  transition: color 0.3s ease;
}
.nav-menu a::after {
  content: '';
  position: absolute;
  bottom: -5px; left: 0;
  width: 0; height: 1px;
  background: linear-gradient(90deg, var(--royal-pink), var(--gold));
  transition: width 0.35s var(--transition-smooth);
}
.nav-menu a:hover { color: var(--soft-pink); }
.nav-menu a:hover::after { width: 100%; }

.header-actions { display: flex; align-items: center; gap: 18px; }
.header-social a {
  color: rgba(255,255,255,0.55);
  font-size: 1rem;
  transition: color 0.25s;
  margin: 0 4px;
  line-height: 1;
}
.header-social a:hover { color: var(--royal-pink); }
.dark-toggle {
  background: none; border: 1px solid rgba(233,30,140,0.35);
  color: var(--soft-pink); width: 34px; height: 34px;
  border-radius: 50%; cursor: none;
  display: flex; align-items: center; justify-content: center;
  transition: all 0.3s ease; font-size: 0.9rem;
}
.dark-toggle:hover { background: rgba(233,30,140,0.15); border-color: var(--royal-pink); }
.equalizer {
  display: flex; align-items: flex-end; gap: 2px; height: 18px;
}
.equalizer span {
  width: 3px;
  background: var(--royal-pink);
  border-radius: 2px;
  will-change: height;
  animation: eqBar 0.7s ease-in-out infinite alternate;
}
.equalizer span:nth-child(1) { animation-delay: 0s; }
.equalizer span:nth-child(2) { animation-delay: 0.12s; }
.equalizer span:nth-child(3) { animation-delay: 0.28s; }
.equalizer span:nth-child(4) { animation-delay: 0.08s; }
@keyframes eqBar {
  0% { height: 4px; opacity: 0.35; }
  100% { height: 16px; opacity: 1; }
}
.hamburger {
  display: none; flex-direction: column; gap: 5px;
  cursor: none; background: none; border: none; padding: 5px;
}
.hamburger span {
  width: 24px; height: 2px;
  background: var(--soft-pink);
  transition: all 0.3s ease;
  border-radius: 2px; display: block;
}

/* Mobile Nav */
.mobile-nav {
  display: none;
  position: fixed; inset: 0;
  background: rgba(8,4,7,0.97);
  backdrop-filter: blur(32px);
  z-index: 9999;
  flex-direction: column;
  align-items: center; justify-content: center;
  gap: 36px;
}
.mobile-nav.open { display: flex; }
.mobile-nav a {
  font-family: var(--font-display);
  font-size: 2rem; color: var(--cream);
  text-decoration: none; letter-spacing: 4px;
  transition: all 0.3s ease;
}
.mobile-nav a:hover { color: var(--royal-pink); text-shadow: 0 0 24px rgba(233,30,140,0.7); }
.mobile-nav-close {
  position: absolute; top: 28px; right: 36px;
  background: none; border: none; color: var(--soft-pink);
  font-size: 2rem; cursor: none;
}

/* ============ HERO ============ */
#hero {
  position: relative; min-height: 100vh;
  display: flex; align-items: center; overflow: hidden;
}
.hero-bg {
  position: absolute; inset: 0;
  background: linear-gradient(135deg, #0a0508 0%, #1a0618 30%, #200a20 55%, #150312 80%, #0a0508 100%);
}
.hero-bg-orb {
  position: absolute; border-radius: 50%;
  filter: blur(70px);
  will-change: transform;
  animation: orbFloat ease-in-out infinite;
}
.hero-orb1 {
  width: 550px; height: 550px;
  background: radial-gradient(circle, rgba(233,30,140,0.22) 0%, transparent 70%);
  top: -120px; right: -80px; animation-duration: 9s;
}
.hero-orb2 {
  width: 380px; height: 380px;
  background: radial-gradient(circle, rgba(212,168,67,0.18) 0%, transparent 70%);
  bottom: -20px; left: -80px; animation-duration: 11s; animation-delay: 2s;
}
.hero-orb3 {
  width: 280px; height: 280px;
  background: radial-gradient(circle, rgba(206,147,216,0.18) 0%, transparent 70%);
  top: 40%; left: 38%; animation-duration: 13s; animation-delay: 4s;
}
@keyframes orbFloat {
  0%, 100% { transform: translate(0, 0) translateZ(0); }
  50% { transform: translate(15px, -25px) translateZ(0); }
}
.hero-particles-canvas { position: absolute; inset: 0; pointer-events: none; }
.hero-content {
  position: relative; z-index: 2;
  display: grid;
  grid-template-columns: 1fr 1fr;
  align-items: center; gap: 60px;
  width: 100%; max-width: 1400px;
  margin: 0 auto; padding: 120px 60px 80px;
}
.hero-text { padding-right: 20px; }
.hero-label {
  font-family: var(--font-body);
  font-size: 0.62rem; letter-spacing: 8px;
  color: var(--gold); text-transform: uppercase;
  margin-bottom: 20px;
  display: flex; align-items: center; gap: 12px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 0.4s;
}
.hero-label::before {
  content: ''; display: block;
  width: 36px; height: 1px; background: var(--gold);
}
@keyframes heroReveal {
  from { opacity: 0; transform: translateY(18px) translateZ(0); }
  to { opacity: 1; transform: translateY(0) translateZ(0); }
}
.hero-title {
  font-family: var(--font-display);
  font-size: clamp(3.2rem, 5.5vw, 6.5rem);
  font-weight: 900; line-height: 1.0;
  margin-bottom: 10px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 0.6s;
  will-change: opacity, transform;
}
.hero-title .gradient-text {
  background: linear-gradient(135deg, var(--royal-pink) 0%, var(--gold) 50%, var(--soft-pink) 100%);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
}
.hero-subtitle {
  font-family: var(--font-script);
  font-size: clamp(1.3rem, 2.5vw, 2.2rem);
  color: var(--gold-light); margin-bottom: 26px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 0.8s;
}
.hero-bio {
  font-family: var(--font-elegant);
  font-size: 1.1rem; line-height: 1.85;
  color: rgba(255,255,255,0.72); margin-bottom: 36px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 1s;
}
.hero-stats {
  display: flex; gap: 36px; margin-bottom: 40px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 1.2s;
}
.hero-stat h3 {
  font-family: var(--font-display); font-size: 2rem; font-weight: 700;
  background: linear-gradient(135deg, var(--gold), var(--royal-pink));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
}
.hero-stat p {
  font-size: 0.62rem; letter-spacing: 3px;
  color: rgba(255,255,255,0.45); text-transform: uppercase;
}
.hero-cta {
  display: flex; gap: 18px; flex-wrap: wrap;
  opacity: 0; animation: heroReveal 0.9s ease forwards 1.4s;
}
.btn-primary {
  display: inline-flex; align-items: center; gap: 9px;
  padding: 13px 34px;
  background: linear-gradient(135deg, var(--royal-pink), var(--deep-pink));
  color: white; font-family: var(--font-body); font-size: 0.7rem;
  font-weight: 600; letter-spacing: 2.5px; text-transform: uppercase;
  text-decoration: none; border-radius: 50px; border: none;
  cursor: none; transition: transform 0.3s ease, box-shadow 0.3s ease;
  box-shadow: 0 6px 24px rgba(233,30,140,0.38);
  will-change: transform;
}
.btn-primary:hover { transform: translateY(-3px) translateZ(0); box-shadow: 0 12px 36px rgba(233,30,140,0.55); }
.btn-outline {
  display: inline-flex; align-items: center; gap: 9px;
  padding: 13px 34px; background: transparent;
  color: var(--soft-pink); font-family: var(--font-body); font-size: 0.7rem;
  font-weight: 600; letter-spacing: 2.5px; text-transform: uppercase;
  text-decoration: none; border-radius: 50px;
  border: 1px solid rgba(233,30,140,0.42);
  cursor: none; transition: all 0.3s ease; backdrop-filter: blur(8px);
  will-change: transform;
}
.btn-outline:hover {
  background: rgba(233,30,140,0.12); border-color: var(--royal-pink);
  transform: translateY(-3px) translateZ(0); box-shadow: 0 8px 24px rgba(233,30,140,0.28);
}
.hero-image-wrap {
  position: relative; display: flex;
  align-items: center; justify-content: center;
  opacity: 0; animation: heroReveal 1.1s ease forwards 0.7s;
}
.hero-image-glow {
  position: absolute; width: 460px; height: 460px;
  background: radial-gradient(circle, rgba(233,30,140,0.28) 0%, transparent 70%);
  animation: glowPulse 4.5s ease-in-out infinite; will-change: transform, opacity;
}
@keyframes glowPulse {
  0%, 100% { transform: scale(1) translateZ(0); opacity: 0.7; }
  50% { transform: scale(1.12) translateZ(0); opacity: 1; }
}
.hero-image-ring {
  position: absolute; border-radius: 50%;
  border: 1px solid rgba(212,168,67,0.25);
  animation: ringExpand 4.5s ease-in-out infinite;
  will-change: transform;
}
.ring1 { width: 400px; height: 400px; animation-delay: 0s; }
.ring2 { width: 460px; height: 460px; animation-delay: 1s; opacity: 0.45; }
.ring3 { width: 520px; height: 520px; animation-delay: 2s; opacity: 0.22; }
@keyframes ringExpand {
  0%, 100% { transform: scale(1) rotate(0deg) translateZ(0); }
  50% { transform: scale(1.04) rotate(4deg) translateZ(0); }
}
.hero-img {
  width: 360px; height: 460px;
  object-fit: cover; object-position: center top;
  border-radius: 40% 60% 60% 40% / 40% 40% 60% 60%;
  position: relative; z-index: 2;
  border: 2px solid rgba(233,30,140,0.35);
  box-shadow: 0 0 50px rgba(233,30,140,0.28), 0 0 100px rgba(212,168,67,0.08);
  animation: heroImgFloat 7s ease-in-out infinite;
  will-change: transform;
}
@keyframes heroImgFloat {
  0%, 100% { transform: translateY(0) translateZ(0); }
  50% { transform: translateY(-12px) translateZ(0); }
}
.hero-badge {
  position: absolute; bottom: 36px; right: -18px;
  background: rgba(255,255,255,0.07);
  backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px);
  border: 1px solid rgba(255,192,203,0.2);
  border-radius: 18px; padding: 14px 20px; z-index: 5;
  animation: badgeFloat 5.5s ease-in-out infinite; will-change: transform;
}
.hero-badge-inner { display: flex; align-items: center; gap: 10px; }
.hero-badge-icon { font-size: 1.6rem; }
.hero-badge h4 { font-family: var(--font-display); font-size: 1rem; color: var(--gold); }
.hero-badge p { font-size: 0.6rem; letter-spacing: 2px; color: rgba(255,255,255,0.55); text-transform: uppercase; }
@keyframes badgeFloat {
  0%, 100% { transform: translateY(0) translateZ(0); }
  50% { transform: translateY(-7px) translateZ(0); }
}
.scroll-indicator {
  position: absolute; bottom: 36px; left: 50%; transform: translateX(-50%);
  display: flex; flex-direction: column; align-items: center; gap: 7px;
  opacity: 0; animation: heroReveal 0.9s ease forwards 1.9s;
}
.scroll-indicator p { font-size: 0.58rem; letter-spacing: 4px; color: rgba(255,255,255,0.35); text-transform: uppercase; }
.scroll-line {
  width: 1px; height: 55px;
  background: linear-gradient(to bottom, var(--royal-pink), transparent);
  animation: scrollLine 2.2s ease-in-out infinite;
  will-change: transform;
}
@keyframes scrollLine {
  0% { transform: scaleY(0) translateZ(0); transform-origin: top; }
  49% { transform: scaleY(1) translateZ(0); transform-origin: top; }
  50% { transform: scaleY(1) translateZ(0); transform-origin: bottom; }
  100% { transform: scaleY(0) translateZ(0); transform-origin: bottom; }
}

/* ============ SECTIONS COMMON ============ */
.section-header { text-align: center; margin-bottom: 65px; }
.section-eyebrow {
  font-family: var(--font-body); font-size: 0.62rem;
  letter-spacing: 8px; color: var(--gold); text-transform: uppercase;
  display: flex; align-items: center; justify-content: center; gap: 14px; margin-bottom: 14px;
}
.section-eyebrow::before, .section-eyebrow::after {
  content: ''; display: block;
  width: 26px; height: 1px; background: var(--gold); opacity: 0.55;
}
.section-title {
  font-family: var(--font-display);
  font-size: clamp(1.9rem, 4vw, 3.3rem);
  font-weight: 700; line-height: 1.15; margin-bottom: 14px;
}
.section-title .accent { color: var(--royal-pink); }
.section-desc {
  font-family: var(--font-elegant); font-size: 1.08rem;
  color: rgba(255,255,255,0.58); max-width: 580px;
  margin: 0 auto; line-height: 1.8;
}
.container { max-width: 1280px; margin: 0 auto; padding: 0 40px; }
section { padding: 100px 0; }

/* ============ ABOUT SECTION ============ */
#about {
  position: relative; overflow: hidden;
  background: linear-gradient(180deg, var(--luxury-black) 0%, #0e0510 50%, var(--luxury-black) 100%);
}
.about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; align-items: center; }
.about-image-wrap { position: relative; }
.about-img {
  width: 100%; border-radius: 28px; object-fit: cover; height: 540px;
  object-position: center top;
  border: 1px solid rgba(233,30,140,0.18);
  filter: brightness(0.92) saturate(1.12) contrast(1.02);
}
.about-img-glow {
  position: absolute; inset: -18px;
  background: radial-gradient(ellipse, rgba(233,30,140,0.13) 0%, transparent 70%);
  border-radius: 38px; z-index: -1;
}
.about-float-badge {
  position: absolute; top: 28px; right: -22px;
  background: linear-gradient(135deg, var(--royal-pink), var(--deep-pink));
  border-radius: 18px; padding: 18px 22px;
  box-shadow: 0 10px 36px rgba(233,30,140,0.48);
  animation: badgeFloat 4.5s ease-in-out infinite;
}
.about-float-badge h3 { font-family: var(--font-display); font-size: 1.9rem; color: white; font-weight: 700; }
.about-float-badge p { font-size: 0.62rem; letter-spacing: 2px; color: rgba(255,255,255,0.82); text-transform: uppercase; }
.about-text h2 { font-family: var(--font-display); font-size: clamp(1.8rem, 3vw, 2.8rem); font-weight: 700; margin-bottom: 18px; }
.about-text h2 em {
  font-style: italic;
  background: linear-gradient(135deg, var(--royal-pink), var(--gold));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
}
.about-text p { font-family: var(--font-elegant); font-size: 1.08rem; line-height: 1.9; color: rgba(255,255,255,0.68); margin-bottom: 18px; }
.about-milestones { display: grid; grid-template-columns: 1fr 1fr; gap: 18px; margin-top: 36px; }
.milestone-card {
  background: var(--glass-bg); border: 1px solid var(--glass-border);
  border-radius: 14px; padding: 18px; backdrop-filter: blur(10px);
  transition: transform 0.3s ease, border-color 0.3s ease, box-shadow 0.3s ease;
  will-change: transform;
}
.milestone-card:hover {
  border-color: rgba(233,30,140,0.38); transform: translateY(-4px) translateZ(0);
  box-shadow: 0 10px 28px rgba(233,30,140,0.18);
}
.milestone-year { font-family: var(--font-display); font-size: 1.4rem; color: var(--gold); font-weight: 700; }
.milestone-desc { font-size: 0.78rem; color: rgba(255,255,255,0.58); line-height: 1.5; margin-top: 5px; }

/* ============ ARTISTS SECTION ============ */
#artists { background: var(--luxury-black); position: relative; }
#artists::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse at 50% 50%, rgba(233,30,140,0.04) 0%, transparent 70%);
}
.artists-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 36px; max-width: 880px; margin: 0 auto; }
.artist-card {
  position: relative; border-radius: 28px; overflow: hidden;
  background: var(--dark-card); border: 1px solid var(--glass-border);
  transition: transform 0.45s var(--transition-smooth), border-color 0.3s ease, box-shadow 0.4s ease;
  will-change: transform; cursor: none;
}
.artist-card:hover {
  transform: translateY(-12px) translateZ(0);
  border-color: rgba(233,30,140,0.45);
  box-shadow: 0 24px 55px rgba(233,30,140,0.22);
}
.artist-img-wrap { position: relative; height: 380px; overflow: hidden; }
.artist-img {
  width: 100%; height: 100%; object-fit: cover; object-position: center top;
  transition: transform 0.55s ease; will-change: transform;
}
.artist-card:hover .artist-img { transform: scale(1.07) translateZ(0); }
.artist-overlay {
  position: absolute; inset: 0;
  background: linear-gradient(to top, rgba(10,5,8,0.96) 0%, rgba(10,5,8,0.25) 45%, transparent 100%);
}
.artist-eq {
  position: absolute; top: 18px; right: 18px;
  display: flex; align-items: flex-end; gap: 2px; height: 22px;
}
.artist-eq span {
  width: 3px; background: var(--royal-pink); border-radius: 2px;
  animation: eqBar 0.6s ease-in-out infinite alternate;
  box-shadow: 0 0 6px var(--royal-pink); will-change: height;
}
.artist-eq span:nth-child(1) { animation-delay: 0.0s; }
.artist-eq span:nth-child(2) { animation-delay: 0.1s; }
.artist-eq span:nth-child(3) { animation-delay: 0.2s; }
.artist-eq span:nth-child(4) { animation-delay: 0.15s; }
.artist-eq span:nth-child(5) { animation-delay: 0.05s; }
.artist-info { padding: 28px; }
.artist-name { font-family: var(--font-display); font-size: 1.7rem; font-weight: 700; margin-bottom: 4px; }
.artist-role { font-size: 0.67rem; letter-spacing: 3.5px; color: var(--gold); text-transform: uppercase; margin-bottom: 13px; }
.artist-bio { font-family: var(--font-elegant); font-size: 0.98rem; color: rgba(255,255,255,0.62); line-height: 1.7; margin-bottom: 18px; }
.artist-socials { display: flex; gap: 10px; flex-wrap: wrap; }
.artist-social-link {
  width: 36px; height: 36px; border-radius: 50%;
  border: 1px solid rgba(233,30,140,0.28);
  display: flex; align-items: center; justify-content: center;
  color: rgba(255,255,255,0.55); text-decoration: none;
  transition: all 0.28s ease; will-change: transform;
}
.artist-social-link svg { width: 16px; height: 16px; fill: currentColor; }
.artist-social-link:hover {
  background: rgba(233,30,140,0.18); border-color: var(--royal-pink);
  color: var(--royal-pink); transform: translateY(-3px) translateZ(0);
  box-shadow: 0 6px 16px rgba(233,30,140,0.3);
}

/* ============ MUSIC / VIDEOS ============ */
#music {
  background: linear-gradient(180deg, var(--luxury-black) 0%, #0e0512 50%, var(--luxury-black) 100%);
  position: relative;
}
.videos-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; }
.video-card {
  background: var(--dark-card); border-radius: 18px; overflow: hidden;
  border: 1px solid var(--glass-border);
  transition: transform 0.35s ease, border-color 0.3s ease, box-shadow 0.35s ease;
  will-change: transform;
}
.video-card:hover {
  transform: translateY(-7px) translateZ(0);
  border-color: rgba(233,30,140,0.38);
  box-shadow: 0 18px 44px rgba(233,30,140,0.18);
}
.video-embed { position: relative; padding-bottom: 56.25%; height: 0; overflow: hidden; }
.video-embed iframe { position: absolute; top: 0; left: 0; width: 100%; height: 100%; border: none; }
.video-info { padding: 18px; }
.video-info h3 { font-family: var(--font-display); font-size: 0.98rem; font-weight: 600; margin-bottom: 5px; }
.video-info p { font-size: 0.72rem; color: rgba(255,255,255,0.48); letter-spacing: 2px; }

/* ============ SPOTIFY SECTION ============ */
#spotify-section {
  background: var(--luxury-black); position: relative; overflow: hidden;
}
#spotify-section::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse at 30% 50%, rgba(29,185,84,0.07) 0%, transparent 60%),
              radial-gradient(ellipse at 70% 50%, rgba(233,30,140,0.07) 0%, transparent 60%);
}
.spotify-inner { display: grid; grid-template-columns: 1.2fr 1fr; gap: 70px; align-items: center; }
.spotify-embed-wrap { position: relative; }
.spotify-glow {
  position: absolute; inset: -28px;
  background: radial-gradient(ellipse, rgba(29,185,84,0.13) 0%, transparent 70%);
  z-index: 0; border-radius: 28px;
}
.spotify-embed-wrap iframe { position: relative; z-index: 1; border-radius: 18px; box-shadow: 0 18px 55px rgba(0,0,0,0.45); }
.spotify-text h2 { font-family: var(--font-display); font-size: clamp(1.9rem, 3.5vw, 2.9rem); margin-bottom: 18px; font-weight: 700; }
.spotify-text p { font-family: var(--font-elegant); font-size: 1.08rem; color: rgba(255,255,255,0.62); line-height: 1.8; margin-bottom: 28px; }
.vinyl {
  width: 160px; height: 160px;
  background: conic-gradient(from 0deg, #1a1a1a, #2e2e2e, #1a1a1a, #3a3a3a, #1a1a1a);
  border-radius: 50%; position: relative;
  animation: spin 9s linear infinite;
  margin: 26px auto;
  box-shadow: 0 0 36px rgba(233,30,140,0.28);
  will-change: transform;
}
.vinyl::before {
  content: ''; position: absolute; inset: 32px;
  background: radial-gradient(circle, var(--royal-pink) 0%, var(--deep-pink) 58%, #1a1a1a 59%);
  border-radius: 50%;
}
.vinyl::after { content: ''; position: absolute; inset: 74px; background: var(--luxury-black); border-radius: 50%; }
@keyframes spin { from { transform: rotate(0deg) translateZ(0); } to { transform: rotate(360deg) translateZ(0); } }
.audio-wave { display: flex; align-items: center; gap: 3px; justify-content: center; margin-top: 18px; }
.audio-wave span {
  width: 4px; border-radius: 4px;
  background: linear-gradient(to top, var(--royal-pink), var(--gold));
  animation: wavePulse 0.9s ease-in-out infinite alternate;
  will-change: height;
}
.audio-wave span:nth-child(1) { animation-delay: 0.0s; }
.audio-wave span:nth-child(2) { animation-delay: 0.1s; }
.audio-wave span:nth-child(3) { animation-delay: 0.2s; }
.audio-wave span:nth-child(4) { animation-delay: 0.3s; }
.audio-wave span:nth-child(5) { animation-delay: 0.4s; }
.audio-wave span:nth-child(6) { animation-delay: 0.3s; }
.audio-wave span:nth-child(7) { animation-delay: 0.2s; }
.audio-wave span:nth-child(8) { animation-delay: 0.1s; }
@keyframes wavePulse { from { height: 6px; } to { height: 36px; } }

/* ============ GALLERY ============ */
#gallery { background: linear-gradient(180deg, var(--luxury-black) 0%, #0e0512 50%, var(--luxury-black) 100%); }
.gallery-masonry { columns: 3; column-gap: 18px; }
.gallery-item {
  break-inside: avoid; margin-bottom: 18px;
  border-radius: 14px; overflow: hidden; position: relative;
  cursor: none; border: 1px solid rgba(255,192,203,0.1);
  transition: transform 0.35s ease, border-color 0.3s ease, box-shadow 0.35s ease;
  will-change: transform;
}
.gallery-item:hover {
  transform: scale(1.02) translateZ(0);
  border-color: rgba(233,30,140,0.38);
  box-shadow: 0 14px 36px rgba(233,30,140,0.18);
}
.gallery-item img {
  width: 100%; display: block;
  transition: transform 0.5s ease; will-change: transform;
  object-fit: cover;
}
.gallery-item:hover img { transform: scale(1.05) translateZ(0); }
.gallery-overlay {
  position: absolute; inset: 0;
  background: linear-gradient(to top, rgba(233,30,140,0.65), rgba(0,0,0,0.15), transparent);
  opacity: 0; transition: opacity 0.3s ease;
  display: flex; align-items: flex-end; padding: 16px;
}
.gallery-item:hover .gallery-overlay { opacity: 1; }
.gallery-overlay span {
  font-size: 0.68rem; letter-spacing: 2.5px; color: white;
  text-transform: uppercase; font-family: var(--font-body);
}

/* ============ PREMIUM GALLERY LIGHTBOX (Instagram-style) ============ */
#lb-overlay {
  position: fixed; inset: 0; z-index: 99990;
  background: rgba(0,0,0,0.96);
  backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px);
  display: none; align-items: center; justify-content: center;
  opacity: 0; transition: opacity 0.35s ease;
}
#lb-overlay.lb-active { display: flex; }
#lb-overlay.lb-visible { opacity: 1; }

/* Desktop: Instagram layout */
.lb-inner {
  display: flex; align-items: stretch;
  background: rgba(18,8,16,0.95);
  border: 1px solid rgba(233,30,140,0.2);
  border-radius: 16px; overflow: hidden;
  max-width: 90vw; max-height: 90vh; width: 1000px;
  box-shadow: 0 30px 80px rgba(0,0,0,0.8), 0 0 0 1px rgba(233,30,140,0.08);
  transform: scale(0.94) translateY(10px);
  transition: transform 0.35s var(--transition-spring), opacity 0.35s ease;
  opacity: 0;
}
#lb-overlay.lb-visible .lb-inner { transform: scale(1) translateY(0); opacity: 1; }

.lb-img-panel {
  flex: 0 0 60%; background: #0a0508;
  display: flex; align-items: center; justify-content: center;
  position: relative; overflow: hidden; min-height: 420px;
}
#lb-img {
  max-width: 100%; max-height: 85vh;
  width: 100%; height: 100%;
  object-fit: contain; object-position: center;
  display: block;
  transition: opacity 0.25s ease;
  image-rendering: high-quality;
}
#lb-img.lb-loading { opacity: 0.3; }

.lb-info-panel {
  flex: 0 0 40%; display: flex; flex-direction: column;
  padding: 28px; overflow-y: auto; border-left: 1px solid rgba(233,30,140,0.12);
  scrollbar-width: thin; scrollbar-color: rgba(233,30,140,0.3) transparent;
}
.lb-info-panel::-webkit-scrollbar { width: 4px; }
.lb-info-panel::-webkit-scrollbar-thumb { background: rgba(233,30,140,0.3); border-radius: 4px; }
.lb-artist {
  display: flex; align-items: center; gap: 12px; margin-bottom: 22px;
  padding-bottom: 18px; border-bottom: 1px solid rgba(255,255,255,0.06);
}
.lb-artist-avatar {
  width: 40px; height: 40px; border-radius: 50%;
  object-fit: cover; border: 2px solid var(--royal-pink);
}
.lb-artist-name { font-family: var(--font-body); font-size: 0.78rem; font-weight: 600; color: white; }
.lb-artist-label { font-size: 0.62rem; letter-spacing: 2px; color: var(--gold); text-transform: uppercase; }
.lb-caption {
  font-family: var(--font-elegant); font-size: 1.08rem; line-height: 1.7;
  color: rgba(255,255,255,0.82); margin-bottom: 16px; flex: 1;
}
.lb-caption strong { color: white; font-weight: 600; }
.lb-meta {
  font-size: 0.65rem; letter-spacing: 3px; color: rgba(255,255,255,0.35);
  text-transform: uppercase; margin-bottom: 20px;
}
.lb-share-row {
  display: flex; gap: 12px; flex-wrap: wrap;
  padding-top: 18px; border-top: 1px solid rgba(255,255,255,0.06);
}
.lb-share-btn {
  display: flex; align-items: center; gap: 7px;
  padding: 8px 16px; border-radius: 50px;
  background: rgba(233,30,140,0.12); border: 1px solid rgba(233,30,140,0.3);
  color: var(--soft-pink); font-size: 0.68rem; letter-spacing: 1.5px;
  text-transform: uppercase; text-decoration: none;
  transition: all 0.25s ease; cursor: none;
}
.lb-share-btn:hover { background: rgba(233,30,140,0.25); }
.lb-share-btn svg { width: 14px; height: 14px; fill: currentColor; }

.lb-close {
  position: absolute; top: 20px; right: 20px;
  background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.12);
  color: white; width: 38px; height: 38px; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  cursor: none; z-index: 10; font-size: 1.1rem;
  transition: all 0.25s ease;
}
.lb-close:hover { background: rgba(233,30,140,0.3); border-color: var(--royal-pink); }

.lb-nav {
  position: absolute; top: 50%; transform: translateY(-50%) translateZ(0);
  background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.12);
  border-radius: 50%; width: 46px; height: 46px;
  display: flex; align-items: center; justify-content: center;
  cursor: none; color: white; font-size: 1.3rem;
  transition: all 0.25s ease; z-index: 5;
  will-change: transform;
}
.lb-nav:hover { background: rgba(233,30,140,0.35); border-color: var(--royal-pink); }
.lb-prev { left: 16px; }
.lb-next { right: 16px; }
.lb-counter {
  position: absolute; bottom: 16px; left: 50%; transform: translateX(-50%);
  font-size: 0.65rem; letter-spacing: 3px; color: rgba(255,255,255,0.45);
  background: rgba(0,0,0,0.5); padding: 5px 12px; border-radius: 20px;
}

/* Mobile lightbox: full screen stack */
@media (max-width: 700px) {
  .lb-inner {
    flex-direction: column; max-width: 100vw; max-height: 100vh;
    width: 100%; border-radius: 0; border: none;
    overflow-y: auto;
  }
  .lb-img-panel { flex: none; min-height: 55vw; max-height: 65vw; }
  #lb-img { max-height: 65vw; }
  .lb-info-panel { flex: none; border-left: none; border-top: 1px solid rgba(233,30,140,0.12); }
  .lb-nav { top: 30%; }
}

/* ============ AWARDS ============ */
#awards { background: var(--luxury-black); position: relative; overflow: hidden; }
#awards::before {
  content: ''; position: absolute; inset: 0;
  background: radial-gradient(ellipse at 50% 50%, rgba(212,168,67,0.05) 0%, transparent 70%);
}
.awards-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 22px; }
.award-card {
  background: var(--glass-bg); border: 1px solid rgba(212,168,67,0.18);
  border-radius: 18px; padding: 32px 22px; text-align: center;
  backdrop-filter: blur(10px); transition: transform 0.35s ease, border-color 0.3s ease, box-shadow 0.35s ease;
  position: relative; overflow: hidden; will-change: transform;
}
.award-card::before {
  content: ''; position: absolute; inset: 0;
  background: linear-gradient(135deg, rgba(212,168,67,0.04), transparent);
  opacity: 0; transition: opacity 0.3s;
}
.award-card:hover::before { opacity: 1; }
.award-card:hover {
  transform: translateY(-7px) translateZ(0);
  border-color: rgba(212,168,67,0.45);
  box-shadow: 0 18px 44px rgba(212,168,67,0.14);
}
.award-icon { font-size: 2.3rem; margin-bottom: 13px; display: block; filter: drop-shadow(0 0 8px rgba(212,168,67,0.45)); }
.award-year { font-family: var(--font-body); font-size: 0.67rem; letter-spacing: 4px; color: var(--gold); text-transform: uppercase; margin-bottom: 9px; }
.award-title { font-family: var(--font-display); font-size: 0.95rem; font-weight: 600; line-height: 1.4; margin-bottom: 7px; }
.award-org { font-size: 0.72rem; color: rgba(255,255,255,0.45); }

/* ============ SOCIAL ICONS (SVG-based) ============ */
.social-icon-svg {
  width: 18px; height: 18px; fill: currentColor; display: block;
  flex-shrink: 0; transition: fill 0.25s ease;
}

/* ============ FOOTER ============ */
#site-footer {
  position: relative;
  background: linear-gradient(to bottom, var(--luxury-black), #04010f);
  border-top: 1px solid rgba(233,30,140,0.08);
  overflow: hidden; padding: 78px 0 0;
}
.footer-glow {
  position: absolute; top: 0; left: 50%; transform: translateX(-50%);
  width: 700px; height: 2px;
  background: linear-gradient(90deg, transparent, var(--royal-pink), var(--gold), var(--royal-pink), transparent);
  opacity: 0.7;
}
.footer-grid {
  display: grid; grid-template-columns: 2fr 1fr 1fr 1.5fr;
  gap: 55px; margin-bottom: 55px; padding: 0 55px;
}
.footer-brand img { height: 56px; margin-bottom: 18px; filter: brightness(1.15); object-fit: contain; width: auto; }
.footer-brand p { font-family: var(--font-elegant); font-size: 0.98rem; color: rgba(255,255,255,0.52); line-height: 1.8; margin-bottom: 22px; }
.footer-social { display: flex; gap: 10px; flex-wrap: wrap; }
.footer-social a {
  width: 40px; height: 40px; border-radius: 50%;
  border: 1px solid rgba(233,30,140,0.28);
  display: flex; align-items: center; justify-content: center;
  color: rgba(255,255,255,0.5); text-decoration: none;
  transition: all 0.28s ease; will-change: transform;
}
.footer-social a svg { width: 17px; height: 17px; fill: currentColor; }
.footer-social a:hover {
  background: rgba(233,30,140,0.18); border-color: var(--royal-pink);
  color: var(--royal-pink); transform: translateY(-4px) translateZ(0);
  box-shadow: 0 7px 18px rgba(233,30,140,0.28);
}
.footer-section h4 { font-family: var(--font-body); font-size: 0.62rem; letter-spacing: 4px; color: var(--gold); text-transform: uppercase; margin-bottom: 22px; }
.footer-links { list-style: none; display: flex; flex-direction: column; gap: 11px; }
.footer-links a {
  font-family: var(--font-elegant); font-size: 0.98rem;
  color: rgba(255,255,255,0.52); text-decoration: none;
  transition: all 0.25s ease; display: flex; align-items: center; gap: 7px;
  will-change: transform;
}
.footer-links a:hover { color: var(--soft-pink); transform: translateX(5px) translateZ(0); }
.footer-newsletter h4 { font-family: var(--font-body); font-size: 0.62rem; letter-spacing: 4px; color: var(--gold); text-transform: uppercase; margin-bottom: 22px; }
.footer-newsletter p { font-family: var(--font-elegant); font-size: 0.98rem; color: rgba(255,255,255,0.52); line-height: 1.7; margin-bottom: 18px; }
.newsletter-form { display: flex; flex-direction: column; gap: 10px; }
.newsletter-input {
  background: rgba(255,255,255,0.04); border: 1px solid rgba(233,30,140,0.18);
  border-radius: 9px; padding: 11px 15px; color: white;
  font-family: var(--font-body); font-size: 0.82rem; outline: none;
  transition: border-color 0.28s ease;
}
.newsletter-input:focus { border-color: rgba(233,30,140,0.45); }
.newsletter-input::placeholder { color: rgba(255,255,255,0.28); }
.newsletter-btn {
  background: linear-gradient(135deg, var(--royal-pink), var(--deep-pink));
  border: none; border-radius: 9px; padding: 12px;
  color: white; font-family: var(--font-body); font-size: 0.68rem;
  font-weight: 600; letter-spacing: 2.5px; text-transform: uppercase;
  cursor: none; transition: transform 0.25s ease, box-shadow 0.25s ease; will-change: transform;
}
.newsletter-btn:hover { transform: translateY(-2px) translateZ(0); box-shadow: 0 7px 22px rgba(233,30,140,0.38); }
.footer-contact-item { display: flex; align-items: flex-start; gap: 11px; margin-bottom: 14px; }
.footer-contact-icon {
  width: 34px; height: 34px; border-radius: 9px;
  background: rgba(233,30,140,0.09); border: 1px solid rgba(233,30,140,0.18);
  display: flex; align-items: center; justify-content: center;
  font-size: 0.8rem; flex-shrink: 0;
}
.footer-contact-item p { font-family: var(--font-elegant); font-size: 0.92rem; color: rgba(255,255,255,0.52); line-height: 1.6; }
.footer-contact-item a { color: rgba(255,255,255,0.52); text-decoration: none; transition: color 0.25s; }
.footer-contact-item a:hover { color: var(--soft-pink); }
.footer-bottom {
  border-top: 1px solid rgba(255,255,255,0.04); padding: 22px 55px;
  display: flex; align-items: center; justify-content: space-between;
  flex-wrap: wrap; gap: 13px;
}
.footer-bottom p { font-size: 0.72rem; color: rgba(255,255,255,0.28); letter-spacing: 1px; }
.footer-bottom .concept { font-family: var(--font-script); font-size: 0.95rem; color: rgba(212,168,67,0.55); }
.ambient-particles { position: absolute; inset: 0; pointer-events: none; overflow: hidden; }
.ambient-particle {
  position: absolute; border-radius: 50%;
  animation: ambientFloat linear infinite; opacity: 0; will-change: transform, opacity;
}
@keyframes ambientFloat {
  0% { transform: translateY(100%) translateZ(0); opacity: 0; }
  10% { opacity: 0.5; }
  90% { opacity: 0.25; }
  100% { transform: translateY(-20px) translateZ(0); opacity: 0; }
}

/* ============ SCROLL REVEAL ============ */
.reveal { opacity: 0; transform: translateY(32px) translateZ(0); transition: opacity 0.75s ease, transform 0.75s ease; will-change: opacity, transform; }
.reveal.visible { opacity: 1; transform: translateY(0) translateZ(0); }

/* ============ RESPONSIVE ============ */
@media (max-width: 1100px) {
  .hero-content { grid-template-columns: 1fr; text-align: center; padding: 110px 40px 75px; }
  .hero-image-wrap { order: -1; }
  .hero-stats { justify-content: center; }
  .hero-cta { justify-content: center; }
  .about-grid { grid-template-columns: 1fr; }
  .about-float-badge { right: 12px; }
  .videos-grid { grid-template-columns: repeat(2, 1fr); }
  .spotify-inner { grid-template-columns: 1fr; }
  .awards-grid { grid-template-columns: repeat(2, 1fr); }
  .footer-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 768px) {
  .nav-menu, .header-social, .equalizer, .dark-toggle { display: none; }
  .hamburger { display: flex; }
  #site-header { padding: 0 22px; }
  .hero-content { padding: 96px 22px 56px; }
  .hero-title { font-size: 2.8rem; }
  .hero-img { width: 280px; height: 360px; }
  .hero-image-glow, .ring1 { width: 310px; height: 310px; }
  .ring2 { width: 360px; height: 360px; }
  .ring3 { width: 410px; height: 410px; }
  .videos-grid { grid-template-columns: 1fr; }
  .artists-grid { grid-template-columns: 1fr; }
  .gallery-masonry { columns: 2; }
  .awards-grid { grid-template-columns: repeat(2, 1fr); }
  .footer-grid { grid-template-columns: 1fr; padding: 0 22px; }
  .footer-bottom { padding: 22px; flex-direction: column; text-align: center; }
  section { padding: 65px 0; }
  .container { padding: 0 22px; }
  .about-milestones { grid-template-columns: 1fr; }
  .hero-badge { right: 0; }
}
@media (max-width: 480px) {
  .hero-stats { flex-wrap: wrap; gap: 18px; }
  .gallery-masonry { columns: 1; }
  .awards-grid { grid-template-columns: 1fr; }
  .hero-img { width: 240px; height: 300px; }
}

body.script:
//

// ===== CONTENT PROTECTION =====
document.addEventListener('contextmenu', function(e){ e.preventDefault(); });
document.addEventListener('keydown', function(e){
  if(e.ctrlKey && (e.key==='u'||e.key==='s'||e.key==='a')) e.preventDefault();
  if(e.key==='F12') e.preventDefault();
  if(e.ctrlKey && e.shiftKey && (e.key==='I'||e.key==='J'||e.key==='C')) e.preventDefault();
});
document.addEventListener('dragstart', function(e){ if(e.target.nodeName==='IMG') e.preventDefault(); });

// ===== DETECT MOUSE / TOUCH =====
document.documentElement.addEventListener('mousemove', function onFirst(){
  document.body.classList.add('has-mouse');
  document.documentElement.removeEventListener('mousemove', onFirst);
}, { once: true });

// ===== CUSTOM CURSOR =====
(function(){
  var cur = document.getElementById('custom-cursor');
  var fol = document.getElementById('cursor-follower');
  if(!cur || !fol) return;
  var mx=0, my=0, fx=0, fy=0;
  document.addEventListener('mousemove', function(e){
    mx = e.clientX; my = e.clientY;
    cur.style.transform = 'translate('+(mx-5)+'px,'+(my-5)+'px) translateZ(0)';
  }, { passive: true });
  (function animFol(){
    fx += (mx-fx)*0.13; fy += (my-fy)*0.13;
    fol.style.transform = 'translate('+(fx-16)+'px,'+(fy-16)+'px) translateZ(0)';
    requestAnimationFrame(animFol);
  })();
  document.querySelectorAll('a,button').forEach(function(el){
    el.addEventListener('mouseenter', function(){
      cur.style.width='18px'; cur.style.height='18px'; cur.style.opacity='0.7';
      fol.style.transform='scale(1.4) translate('+(fx-16)+'px,'+(fy-16)+'px)';
      fol.style.borderColor='rgba(233,30,140,0.7)';
    });
    el.addEventListener('mouseleave', function(){
      cur.style.width='10px'; cur.style.height='10px'; cur.style.opacity='1';
      fol.style.borderColor='rgba(233,30,140,0.45)';
    });
  });
})();

// ===== PRELOADER =====
(function(){
  var bar = document.getElementById('preloaderBar');
  var pct = document.getElementById('preloaderPercent');
  var loader = document.getElementById('preloader');
  var pp = document.getElementById('preloaderParticles');
  // Particles
  if(pp){
    var colors = ['#d4a843','#e91e8c','#f7d976','#f48fb1','#ce93d8'];
    for(var i=0; i<20; i++){
      var p = document.createElement('div');
      p.className = 'preloader-particle';
      p.style.cssText = 'left:'+Math.random()*100+'%;width:'+(Math.random()*3+2)+'px;height:'+(Math.random()*3+2)+'px;animation-duration:'+(Math.random()*3+3)+'s;animation-delay:'+(Math.random()*2)+'s;background:'+colors[Math.floor(Math.random()*colors.length)];
      pp.appendChild(p);
    }
  }
  // Progress
  var count = 0;
  var iv = setInterval(function(){
    count += Math.random()*4+2;
    if(count>=100) count=100;
    bar.style.width = count+'%';
    pct.textContent = Math.floor(count)+'%';
    if(count>=100){
      clearInterval(iv);
      setTimeout(function(){
        loader.style.transition='opacity 0.7s ease';
        loader.style.opacity='0';
        setTimeout(function(){ loader.style.display='none'; }, 700);
      }, 250);
    }
  }, 35);
})();

// ===== HEADER SCROLL =====
(function(){
  var header = document.getElementById('site-header');
  var ticking = false;
  window.addEventListener('scroll', function(){
    if(!ticking){
      requestAnimationFrame(function(){
        header.classList.toggle('scrolled', window.scrollY > 50);
        ticking = false;
      });
      ticking = true;
    }
  }, { passive: true });
})();

// ===== MOBILE NAV =====
var mobileNav = document.getElementById('mobileNav');
document.getElementById('hamburgerBtn').addEventListener('click', function(){ mobileNav.classList.add('open'); });
document.getElementById('mobileNavClose').addEventListener('click', function(){ mobileNav.classList.remove('open'); });
function closeMobileNav(){ mobileNav.classList.remove('open'); }

// ===== DARK/LIGHT TOGGLE =====
(function(){
  var isDark = true;
  document.getElementById('darkToggle').addEventListener('click', function(){
    isDark = !isDark;
    var logo = document.getElementById('headerLogo');
    if(isDark){
      document.documentElement.style.setProperty('--luxury-black','#0a0508');
      document.documentElement.style.setProperty('--dark-surface','#120a10');
      if(logo) logo.src='https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEjfK_Q4rScuzR4C8MMGuqPh-KQE3sv8SFszKyRujbNjGIJg8orY5s0_7q8x6xBfWvpjuuDhvqOZqaWUZXBNp71ISPWyFlatwyuwT_YUyF54IJfWelQOzyi60yh99HvkWS3IsXMQ8ZuxgCUGJq9CPq9vDHYQijYU_gypVwPR5JS_a5sSvCg65FUqQC6h_Qw/s320/logo%201.jpg';
      this.textContent='\u263E'; document.body.style.color='';
    } else {
      document.documentElement.style.setProperty('--luxury-black','#fdf6f0');
      document.documentElement.style.setProperty('--dark-surface','#f0e4ec');
      document.body.style.color='#1a0618';
      if(logo) logo.src='https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhN4tiBsz1FwLDJzfD43FUeUTo5e188TSq5xLjOA81NW2tB-vxBeBbtPbCvT7NZeYXXsFACr1zLKTam-s9QrmiUI73GsfYfuEvqQRRn98H8UhEvMyDB9lzGwrVwTJQKMyq7nn87THWS0Lrbyp2K35ACjVXH5PAGYev5DGfSMKwSTt1kkaObOdPPJRc61NI/s1600/325291176_645462420602927_817374684450874339_n.jpg';
      this.textContent='\u2600';
    }
  });
})();

// ===== HERO CANVAS =====
(function(){
  var canvas = document.getElementById('heroCanvas');
  if(!canvas) return;
  var ctx = canvas.getContext('2d');
  var W, H, pts=[];
  function resize(){ W=canvas.width=canvas.offsetWidth; H=canvas.height=canvas.offsetHeight; }
  resize();
  var ro = new ResizeObserver(resize);
  ro.observe(canvas.parentElement);
  var cols=['rgba(233,30,140,','rgba(212,168,67,','rgba(244,143,177,','rgba(206,147,216,'];
  for(var i=0;i<60;i++){
    pts.push({x:Math.random()*1200,y:Math.random()*800,r:Math.random()*1.8+0.4,dx:(Math.random()-.5)*.35,dy:(Math.random()-.5)*.35,o:Math.random()*.5+0.1,c:cols[Math.floor(Math.random()*cols.length)]});
  }
  function draw(){
    ctx.clearRect(0,0,W,H);
    pts.forEach(function(p){
      ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      ctx.fillStyle=p.c+p.o+')'; ctx.fill();
      p.x+=p.dx; p.y+=p.dy;
      if(p.x<0||p.x>W) p.dx*=-1;
      if(p.y<0||p.y>H) p.dy*=-1;
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

// ===== SCROLL REVEAL =====
(function(){
  var obs = new IntersectionObserver(function(entries){
    entries.forEach(function(e){ if(e.isIntersecting) e.target.classList.add('visible'); });
  }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });
  document.querySelectorAll('.reveal').forEach(function(el){ obs.observe(el); });
})();

// ===== PREMIUM GALLERY LIGHTBOX =====
(function(){
  var galleryItems = document.querySelectorAll('.gallery-item');
  var overlay = document.getElementById('lb-overlay');
  var lbImg = document.getElementById('lb-img');
  var lbCaption = document.getElementById('lbCaption');
  var lbMeta = document.getElementById('lbMeta');
  var lbCounter = document.getElementById('lbCounter');
  var lbClose = document.getElementById('lbClose');
  var lbPrev = document.getElementById('lbPrev');
  var lbNext = document.getElementById('lbNext');
  if(!overlay) return;

  var images = [];
  var current = 0;

  galleryItems.forEach(function(item, i){
    var img = item.querySelector('img');
    var caption = item.getAttribute('data-caption') || 'African Princess Label';
    images.push({ src: img.src, caption: caption });
    item.addEventListener('click', function(){ openLB(i); });
    item.style.cursor = 'pointer';
  });

  function openLB(idx){
    current = idx;
    overlay.classList.add('lb-active');
    requestAnimationFrame(function(){
      requestAnimationFrame(function(){ overlay.classList.add('lb-visible'); });
    });
    loadImage(current);
    document.body.style.overflow = 'hidden';
  }

  function closeLB(){
    overlay.classList.remove('lb-visible');
    setTimeout(function(){ overlay.classList.remove('lb-active'); }, 350);
    document.body.style.overflow = '';
  }

  function loadImage(idx){
    if(!images[idx]) return;
    lbImg.classList.add('lb-loading');
    var tempImg = new Image();
    tempImg.onload = function(){
      lbImg.src = images[idx].src;
      lbImg.classList.remove('lb-loading');
    };
    tempImg.src = images[idx].src;
    if(lbCaption) lbCaption.textContent = images[idx].caption;
    if(lbCounter) lbCounter.textContent = (idx+1) + ' / ' + images.length;
    if(lbMeta) lbMeta.textContent = 'African Princess Label \u2022 Nandy';
  }

  function goNext(){ current=(current+1)%images.length; loadImage(current); }
  function goPrev(){ current=(current-1+images.length)%images.length; loadImage(current); }

  lbClose.addEventListener('click', closeLB);
  lbNext.addEventListener('click', function(e){ e.stopPropagation(); goNext(); });
  lbPrev.addEventListener('click', function(e){ e.stopPropagation(); goPrev(); });
  overlay.addEventListener('click', function(e){
    if(e.target===overlay) closeLB();
  });

  // Keyboard
  document.addEventListener('keydown', function(e){
    if(!overlay.classList.contains('lb-active')) return;
    if(e.key==='ArrowRight'||e.key==='ArrowDown') goNext();
    if(e.key==='ArrowLeft'||e.key==='ArrowUp') goPrev();
    if(e.key==='Escape') closeLB();
  });

  // Touch/swipe
  var touchStartX = 0, touchStartY = 0;
  overlay.addEventListener('touchstart', function(e){ touchStartX=e.touches[0].clientX; touchStartY=e.touches[0].clientY; }, { passive: true });
  overlay.addEventListener('touchend', function(e){
    var dx = e.changedTouches[0].clientX - touchStartX;
    var dy = e.changedTouches[0].clientY - touchStartY;
    if(Math.abs(dx)>Math.abs(dy) && Math.abs(dx)>40){
      if(dx>0) goPrev(); else goNext();
    }
  }, { passive: true });
})();

// ===== PARALLAX ORBS =====
(function(){
  var orbs = document.querySelectorAll('.hero-bg-orb');
  document.addEventListener('mousemove', function(e){
    var xFrac = e.clientX/window.innerWidth - 0.5;
    var yFrac = e.clientY/window.innerHeight - 0.5;
    orbs.forEach(function(orb, i){
      var f = (i+1)*0.35;
      orb.style.transform = 'translate('+(xFrac*f*20)+'px,'+(yFrac*f*20)+'px) translateZ(0)';
    });
  }, { passive: true });
})();

// ===== FOOTER PARTICLES =====
(function(){
  var fp = document.getElementById('footerParticles');
  if(!fp) return;
  var colors = ['#e91e8c','#d4a843','#f48fb1','#ce93d8'];
  for(var i=0;i<16;i++){
    var p = document.createElement('div');
    p.className = 'ambient-particle';
    p.style.cssText='left:'+Math.random()*100+'%;bottom:0;width:'+(Math.random()*3+2)+'px;height:'+(Math.random()*3+2)+'px;background:'+colors[Math.floor(Math.random()*colors.length)]+';animation-duration:'+(Math.random()*5+4)+'s;animation-delay:'+(Math.random()*4)+'s';
    fp.appendChild(p);
  }
})();

//
